// Récupère le feed courant depuis le context de la boucle
const feedData = $('Loop Over Items').first().json;
const feedName = feedData.name || 'Source inconnue';

// Filtre les articles des dernières 24h (ou 5 jours pour tests)
const now = new Date();
const cutoffDate = new Date(now.getTime() - 24 * 60 * 60 * 1000); // 24h
// const cutoffDate = new Date(now.getTime() - 5 * 24 * 60 * 60 * 1000); // 5 jours (pour tests)

const recentArticles = $input.all()
  .filter(item => {
    const pubDate = new Date(item.json.pubDate || item.json.isoDate || 0);
    return pubDate >= cutoffDate;
  })
  .map(item => ({
    json: {
      feedName,
      title: item.json.title || 'Sans titre',
      link: item.json.link || '',
      pubDate: item.json.pubDate || item.json.isoDate || '',
      content: (item.json.contentSnippet || item.json.content || item.json.description || '').substring(0, 500)
    }
  }));

// Retourne un item vide si aucun article (pour continuer la boucle)
if (recentArticles.length === 0) {
  return [{ json: { _empty: true, feedName } }];
}

return recentArticles;

// Agrège tous les articles de toutes les itérations
const allItems = $input.all();

const articles = allItems
  .map(item => item.json)
  .filter(article => !article._empty && article.title);

if (articles.length === 0) {
  return [{ json: { hasArticles: false, articles: [], articleCount: 0 } }];
}

return [{ json: { hasArticles: true, articles, articleCount: articles.length } }];

// 📝 Configure tes flux RSS ici
const rssFeeds = [
  { name: "Swift by Sundell", url: "https://www.swiftbysundell.com/rss" },
  { name: "Hacking with Swift", url: "https://www.hackingwithswift.com/articles/rss" },
  { name: "iOS Dev Weekly", url: "https://iosdevweekly.com/issues.rss" },
  { name: "Donny Wals", url: "https://www.donnywals.com/feed/" },
  { name: "SwiftLee", url: "https://www.avanderlee.com/feed/" }
];

return rssFeeds.map(feed => ({ json: feed }));

const articles = $json.articles;
const articleCount = $json.articleCount;

// Organise par source
const bySource = {};
articles.forEach(article => {
  const source = article.feedName || 'Autre';
  if (!bySource[source]) bySource[source] = [];
  bySource[source].push(article);
});

let articlesText = '';
for (const [source, items] of Object.entries(bySource)) {
  articlesText += `\n## ${source}\n`;
  items.forEach((article, i) => {
    articlesText += `\n### ${i + 1}. ${article.title}\nURL: ${article.link}\nExtrait: ${article.content}...\n`;
  });
}

const prompt = `### ROLE
You are a Senior iOS & Swift Architect specialized in tech intelligence. Your goal is to filter signal from noise and provide a high-value daily digest for developers.

### CONTEXT
Trigger: Daily 8:00 AM automated sync.
Input Data: Recently published tech articles from various sources.
Articles to process: 
${articlesText}

### OBJECTIVE
Summarize the provided articles while strictly adhering to the original language of each source (English, French, or Japanese). Group them by relevant technical categories.

### CONSTRAINTS & FORMATTING RULES
1. LANGUAGE: Summarize in French if the article is French, in English if English, and in Japanese if Japanese.
2. NO MARKDOWN: Do NOT use any markdown formatting (no asterisks **, no underscores _, no headers #). Use only plain text and emojis.
3. URL: Always include the article's URL at the end of its summary.
4. SPACING: Leave one empty line between each article for readability.

### RESPONSE STRUCTURE
🔥 POINTS CLES
(Provide 3 to 5 bullet points summarizing the most critical trends from all articles combined)

📱 PAR CATEGORIE
[Category Name - e.g., Swift, SwiftUI, iOS, Architecture, Testing, VisionPro...]

- [Article Title]
[2-3 sentence summary in the source's original language]
🔗 [URL]

- [Next Article Title]
...

### EXAMPLE OF SUMMARY LANGUAGE ADHERENCE
- If source is EN: "Apple released Swift 6.0 with new concurrency features..."
- If source is FR: "Apple a publié Swift 6.0 avec de nouvelles fonctionnalités de concurrence..."
- If source is JP: "Appleは、新しい並行処理機能を備えたSwift 6.0をリリースしました..."`;

return [{ json: { prompt, articleCount } }];

